/**
 * Security Service
 * 
 * Handles security-related operations including PIN management, two-factor
 * authentication setup and verification, token refresh, and user data synchronization.
 * Manages security PIN operations and 2FA QR code generation for authenticator apps.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import { profileService } from './profileService.js';
import logger from '@/shared/utils/logger.js';

export const securityService = {
  /**
   * Refreshes user data by fetching the latest profile information from the API.
   * Merges the new data with existing localStorage data and updates the stored user data.
   * @returns {Promise<Object|null>} Updated user data or null if profile fetch fails
   */
  async refreshUserData() {
    try {
      const profileData = await profileService.getUserProfile();

      if (profileData && profileData.data) {
        const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Preserve the original login user ID - don't let profile data overwrite it
        const preservedId = currentUserData.id;
        const { id: profileId, ...profileDataWithoutId } = profileData.data;
        const updatedUserData = {
          ...currentUserData,
          ...profileDataWithoutId,
          id: preservedId // Always preserve the login user ID
        };
        localStorage.setItem('userData', JSON.stringify(updatedUserData));

        return updatedUserData;
      }

      return null;
    } catch (error) {
      throw error;
    }
  },
  /**
   * Sets a new security PIN for transaction authentication.
   * @param {string} pin - The 4-digit PIN to set
   * @returns {Promise<Object>} API response confirming PIN setup
   */
  async setSecurityPIN(pin) {
    const pinData = await apiRequest('/auth/profile/set-pin', {
      method: 'PUT',
      body: JSON.stringify({
        pin: pin,
      }),
    });

    return pinData;
  },

  /**
   * Verifies a security PIN for transaction authorization.
   * @param {string} pin - The 4-digit PIN to verify
   * @returns {Promise<Object>} API response confirming PIN verification
   */
  async verifySecurityPIN(pin) {
    const verifyData = await apiRequest('/auth/profile/verify-pin', {
      method: 'POST',
      body: JSON.stringify({ pin }),
    });
    return verifyData;
  },

  /**
   * Refreshes the authentication token using the stored refresh token.
   * Implements retry logic with exponential backoff for failed refresh attempts.
   * Updates both access and refresh tokens in localStorage upon success.
   * @param {number} maxRetries - Maximum number of retry attempts (default: 2)
   * @param {number} delay - Delay in milliseconds between retries (default: 1000)
   * @returns {Promise<Object>} Token refresh response with new tokens
   * @throws {Error} If refresh fails after all retries or no refresh token is available
   */
  async refreshAuthToken(maxRetries = 2, delay = 1000) {
    logger.debug('Refreshing auth token');

    const refreshToken = localStorage.getItem('refreshToken');
    if (!refreshToken) {
      logger.error('No refresh token available');
      throw new Error('Session expired. Please log in again.');
    }

    let lastError;
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        if (attempt > 0) {
          logger.debug(`Retry attempt ${attempt} in ${delay}ms`);
          await new Promise(resolve => setTimeout(resolve, delay));
        }

        logger.debug(`Token refresh attempt ${attempt + 1}/${maxRetries + 1}`);

        const response = await Promise.race([
          apiRequest('/publicauth/token/refresh', {
            method: 'POST',
            body: JSON.stringify({ refresh: refreshToken }),
            headers: {
              'X-Skip-Auth': '1'
            }
          }),
          new Promise((_, reject) =>
            setTimeout(() => reject(new Error('Request timed out.')), 10000)
          )
        ]);

        // Handle different response structures with proper null checking
        const tokens = response?.data?.tokens || response?.tokens || {};
        const newToken = tokens?.accessToken ||
          response?.accessToken ||
          response?.token ||
          response?.access;
        const newRefresh = tokens?.refreshToken ||
          response?.refreshToken ||
          response?.refresh;

        if (newToken) {
          localStorage.setItem('authToken', newToken);
          // Update token expiry when refreshing - set to 24 hours from now
          localStorage.setItem('tokenExpiry', Date.now() + (24 * 60 * 60 * 1000));

          if (newRefresh) {
            localStorage.setItem('refreshToken', newRefresh);
          }

          logger.debug('Token refresh successful');
          return {
            accessToken: newToken,
            refreshToken: newRefresh,
            ...response
          };
        }

        throw new Error('Invalid token refresh response structure');
      } catch (error) {
        logger.warn(`Token refresh attempt ${attempt + 1} failed`, { error: error.message });
        lastError = error;

        if (error.response?.status === 401 || error.response?.status === 403) {
          logger.error('Authentication failed, refresh token might be invalid');
          break;
        }
      }
    }

    logger.error('All token refresh attempts failed');
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');

    throw lastError || new Error('Failed to refresh session. Please log in again.');
  },

  /**
   * Enables two-factor authentication for the authenticated user.
   * Generates a QR code for authenticator app setup and returns the secret and QR code.
   * Checks authentication status before proceeding.
   * @returns {Promise<Object>} 2FA setup data including QR code and secret
   * @throws {Error} If user is not authenticated or QR code generation fails
   */
  async enable2FA() {
    logger.debug('enable2FA service called');

    const authToken = localStorage.getItem('authToken');
    if (!authToken) {
      logger.error('User is not authenticated');
      if (window.location.pathname !== '/login') {
        window.location.href = '/login?redirect=' + encodeURIComponent(window.location.pathname);
      }
      throw new Error('Your session has expired. Please log in again to enable 2FA.');
    }

    try {
      logger.debug('Making API request to /auth/profile/enable-2FA');

      const response = await apiRequest('/auth/profile/enable-2FA', {
        method: 'GET',
        timeout: 30000
      });

      logger.debug('2FA enable response received', { response });

      if (!response || !response.data) {
        throw new Error('Invalid response from server');
      }

      if (response.data.qrCode) {
        logger.debug('Processing QR code');
        if (!response.data.qrCode.startsWith('data:')) {
          response.data.qrCode = `data:image/png;base64,${response.data.qrCode}`;
          logger.debug('QR code formatted with data URI prefix');
        }
      } else {
        logger.warn('No QR code in response data');
        throw new Error('Failed to generate 2FA QR code');
      }

      logger.debug('Returning 2FA data');
      return response;
    } catch (error) {
      logger.error('enable2FA error', { error });
      throw error;
    }
  },

  /**
   * Disables two-factor authentication for the authenticated user.
   * @returns {Promise<Object>} API response confirming 2FA disable
   */
  async disable2FA() {
    const disableData = await apiRequest('/auth/profile/disable-2FA', {
      method: 'GET',
      timeout: 30000,
    });

    return disableData;
  },

  /**
   * Verifies a two-factor authentication code from the authenticator app.
   * Attempts to retrieve customer ID from localStorage or profile API if not provided.
   * @param {string} authCode - The 6-digit code from the authenticator app
   * @param {string|null} customerIdOverride - Optional customer ID (auto-detected if not provided)
   * @returns {Promise<Object>} API response confirming 2FA verification
   * @throws {Error} If customer ID cannot be determined or verification fails
   */
  async verifyTwoFactorAuth(authCode, customerIdOverride = null) {
    let customerId = customerIdOverride;

    if (!customerId) {
      try {
        const userData = JSON.parse(localStorage.getItem('userData') || '{}');
        customerId = userData?.id || userData?.user?.id || null;
      } catch (error) {
        logger.error('Error parsing user data', { error });
        customerId = null;
      }
    }

    if (!customerId) {
      try {
        const profileData = await profileService.getUserProfile();
        customerId = profileData?.data?.user?.id || profileData?.data?.id || null;
      } catch (error) {
        logger.error('Error fetching user profile', { error });
      }
    }

    if (!customerId) {
      throw new Error('Unable to resolve user ID for 2FA verification. Please re-login and try again.');
    }

    try {
      const accountSecurity = await this.getAccountSecurity();
      const is2FAEnabled = accountSecurity?.data?.twoFaEnabled ||
        accountSecurity?.data?.is2FAEnabled ||
        accountSecurity?.twoFaEnabled ||
        false;

      if (!is2FAEnabled) {
        throw new Error('Two-factor authentication is not enabled for your account. Please enable 2FA first.');
      }
    } catch (error) {
      logger.warn('Could not verify 2FA status, proceeding with verification attempt', { error });
    }

    const payload = {
      code: authCode.toString().trim(),
      customerId: customerId.toString()
    };

    logger.debug('Verifying 2FA with payload', { payload });

    try {
      const data = await apiRequest('/publicauth/verify-2fa', {
        method: 'POST',
        body: JSON.stringify(payload),
        skipAuth: true,
        headers: {
          'Content-Type': 'application/json'
        },
        timeout: 30000
      });

      return data;
    } catch (error) {
      if (error.message.includes('2FA is not enabled') ||
        (error.response && error.response.body &&
          JSON.parse(error.response.body).message === '2FA is not enabled')) {
        throw new Error('Two-factor authentication is not enabled for your account. Please enable 2FA first.');
      }

      throw error;
    }
  },

  /**
   * Requests a phone verification OTP to be sent to the user's phone number.
   * @param {string} type - The type of phone OTP request (e.g., 'customer', 'business')
   * @returns {Promise<Object>} API response containing OTP delivery confirmation
   */
  async requestPhoneOTP(type) {
    const otpData = await apiRequest(`/api/publicauth/request-verify-phone-otp/${type}`, {
      method: 'GET',
    });

    return otpData;
  },

  /**
   * Retrieves the current security settings for the authenticated user.
   * Returns information about PIN status, 2FA status, and other security features.
   * @returns {Promise<Object>} Account security data including PIN and 2FA status
   */
  async getAccountSecurity() {
    const data = await apiRequest('/auth/profile/security', {
      method: 'GET',
    });
    return data;
  },
};

export default securityService;
